INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 10021, 1, 24, 24015, 0.0, 110501, 0.0, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 4, 4);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 10021, 2, 24, 24016, 0.0, 110501, 4.0, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 1, 4);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("マジムンだらけで目が回るさ～！\nふらふらさ～！", 10021, 3, 24, 24017, 0.0, 110501, 0.0, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 4, 4);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 10021, 4, 24, 24018, 0.0, 110501, 5.2, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 2, 1);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 10021, 5, 24, 24019, 0.0, 110501, 4.2, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 6, 5);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 10021, 6, 24, 24020, 0.0, 110501, 0.0, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 2, 2);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 10021, 7, 24, 24021, 0.0, 110501, 6.4, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 6, 1);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 10021, 8, 24, 24022, 0.0, 110501, 0.0, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 2, 2);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 10021, 9, 24, 24023, 0.0, 110501, 10.08, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 3, 6);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 10021, 10, 24, 24024, 0.0, 110501, 5.0, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 2, 1);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 10021, 11, 24, 24025, 0.0, 110501, 0.0, "2019/07/31 12:00:00", "2030/12/17 14:59:59", 0.0, "カオリ（サマー）", 2, 2);
